import{_ as r,o as a,c as t,a2 as o}from"./chunks/framework.Bix3-HpO.js";const p=JSON.parse('{"title":"Theme Breadcrumbs","description":"Akurai Theme Breadcrumbs","frontmatter":{"title":"Theme Breadcrumbs","description":"Akurai Theme Breadcrumbs","weight":110,"extra":{"order":110},"head":[["link",{"rel":"canonical","href":"https://docs.dinomatic.com/docs/akurai/breadcrumbs"}],["meta",{"property":"og:url","content":"https://docs.dinomatic.com/docs/akurai/breadcrumbs"}],["meta",{"property":"og:title","content":"Theme Breadcrumbs"}],["meta",{"property":"og:description","content":"Akurai Theme Breadcrumbs"}],["meta",{"name":"twitter:title","content":"Theme Breadcrumbs"}],["meta",{"name":"twitter:description","content":"Akurai Theme Breadcrumbs"}]]},"headers":[],"relativePath":"docs/akurai/breadcrumbs.md","filePath":"docs/akurai/breadcrumbs.md"}'),s={name:"docs/akurai/breadcrumbs.md"};function c(n,e,d,u,i,m){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="akurai-breadcrumbs" tabindex="-1">Akurai Breadcrumbs <a class="header-anchor" href="#akurai-breadcrumbs" aria-label="Permalink to &quot;Akurai Breadcrumbs&quot;">​</a></h1><p>Akurai theme comes with built-in breadcrumbs since version 1.0.9.</p><hr><h3 id="enable-breadcrumbs" tabindex="-1">Enable Breadcrumbs <a class="header-anchor" href="#enable-breadcrumbs" aria-label="Permalink to &quot;Enable Breadcrumbs&quot;">​</a></h3><p>To add breadcrumbs to your website you need to enable them. In your WordPress dashboard visit <strong>Appearance</strong> → <strong>Customizer</strong> → <strong>Breadcrumbs Options</strong> to enable breadcrumbs as well as adjust settings.</p><p><img src="https://media.dinomatic.com/images/docs/akurai/customizer/breadcrumbs-options.png" alt="Akurai Breadcrumbs"></p><h3 id="breadcrumbs-options" tabindex="-1">Breadcrumbs Options <a class="header-anchor" href="#breadcrumbs-options" aria-label="Permalink to &quot;Breadcrumbs Options&quot;">​</a></h3><p><strong>Reviews page Parent page</strong></p><p>Akurai doesn&#39;t enforce users to have a parent page for review pages, however you can set one in breadcrumbs if you want.</p><p><strong>Blog posts</strong></p><p>By default breadcrumbs for posts pages includes categories, however you can add blog page as well. Just make sure to check the box <em>Include blog page in posts breadcrumbs</em>.</p><h3 id="schema-org-markup" tabindex="-1">Schema.org markup <a class="header-anchor" href="#schema-org-markup" aria-label="Permalink to &quot;Schema.org markup&quot;">​</a></h3><p>Akurai also includes structured data (schema.org) markup for <a href="https://developers.google.com/search/docs/data-types/breadcrumb" target="_blank" rel="noreferrer">breadcrumbs</a> out of the box, so you don&#39;t need to do anything.</p><blockquote><p><strong>Do not enable breadcrumbs option in Yoast, as you&#39;ll end up having duplicate markup.</strong></p></blockquote>',14)])])}const l=r(s,[["render",c]]);export{p as __pageData,l as default};
